~L2
#svc {lst:["auth","billing","search","notifications"]}
#rpt {items:[] ok:0 fl:0}
^ea {$svc.lst} ->$s <<
  ?vfy @net {svc:$s kind:"health"} ->$h
  ^if {$h.hlt} <<
    !mod @mem {obj:$rpt.items add:{svc:$s st:"ok"}}
    !mod @mem {obj:$rpt.ok add:1}
  >> ^el <<
    !mod @mem {obj:$rpt.items add:{svc:$s st:"fl"}}
    !mod @mem {obj:$rpt.fl add:1}
  >>
>>
>ok {report:$rpt}

